module data_type_examples;
    // Net types
    wire        single_wire;
    wire [7:0]  data_bus;
    wire [31:0] address;

    // Variable types
    reg         flag;
    reg [15:0]  counter;
    reg [7:0]   byte_reg;

    // Integer (32-bit signed)
    integer     loop_index;
    integer     count = 0;

    // Signed declarations
    reg signed [7:0]  signed_data;
    wire signed [15:0] signed_result;

    // Parameters
    parameter WIDTH = 8;
    parameter DEPTH = 256;
    localparam ADDR_WIDTH = $clog2(DEPTH);  // = 8

endmodule

module number_formats;
    // Format: <size>'<base><value>

    // Binary
    wire [7:0] bin1 = 8'b10101010;
    wire [7:0] bin2 = 8'b1010_1010;  // Underscore for readability

    // Hexadecimal
    wire [7:0] hex1 = 8'hAA;
    wire [15:0] hex2 = 16'hDEAD;

    // Decimal
    wire [7:0] dec1 = 8'd170;
    wire [7:0] dec2 = 170;  // Size inferred (32-bit default)

    // Octal
    wire [7:0] oct1 = 8'o252;

    // Special values
    wire [7:0] unknown = 8'bxxxx_xxxx;  // All X
    wire [7:0] highz = 8'bzzzz_zzzz;    // All Z
    wire [7:0] partial = 8'b1010_xxxx;  // Partial unknown

    // Negative numbers
    wire signed [7:0] neg = -8'd5;

    // All same value: 170
    // 8'b10101010 = 8'hAA = 8'd170 = 8'o252

endmodule

module vectors_and_arrays;
    // Vector declarations
    wire [7:0]  byte_data;      // 8-bit, byte_data[7] is MSB
    reg  [31:0] word_data;      // 32-bit register
    wire [15:0] half_word;      // 16-bit

    // Vector part-select
    wire        msb = byte_data[7];       // Single bit
    wire [3:0]  upper = byte_data[7:4];   // Upper nibble
    wire [3:0]  lower = byte_data[3:0];   // Lower nibble

    // Memory array (256 bytes)
    reg [7:0] memory [0:255];

    // Memory operations
    initial begin
        memory[0] = 8'hFF;        // Write to address 0
        memory[100] = 8'hAB;      // Write to address 100
    end

    // Read from memory
    wire [7:0] read_data;
    reg [7:0] addr;
    assign read_data = memory[addr];

    // 2D array (4x4 matrix of bytes)
    reg [7:0] matrix [0:3][0:3];

    // Register file (32 registers, 32-bit each)
    reg [31:0] reg_file [0:31];

endmodule

module wire_vs_reg_demo (
    input  wire       clk,
    input  wire       sel,
    input  wire [7:0] a, b,
    output wire [7:0] combo_out,   // Wire: driven by assign
    output reg  [7:0] seq_out,     // Reg: driven in always
    output reg  [7:0] combo_reg    // Reg: but still combinational!
);

    // Wire driven by continuous assignment
    assign combo_out = sel ? a : b;

    // Reg driven in sequential always block
    always @(posedge clk) begin
        seq_out <= a + b;  // This synthesizes to a register
    end

    // Reg driven in combinational always block
    always @(*) begin
        if (sel)
            combo_reg = a;  // This synthesizes to MUX, not register!
        else
            combo_reg = b;
    end

    // RULE: reg does NOT mean hardware register
    // reg = assigned in always/initial blocks
    // wire = assigned by assign or module outputs

endmodule
